final:
module mux4to1 (
    output reg mux_Y,
    input A,
    input B,
    input C,
    input D,
    input S0,
    input S1
);

    always @(*) begin
        case ({S1, S0})
            2'b00: mux_Y = A;
            2'b01: mux_Y = B;
            2'b10: mux_Y = C;
            2'b11: mux_Y = D;
        endcase
    end

endmodule
